class Solution(object):
    def closestCost(self, baseCosts, toppingCosts, target):
        possible = set(baseCosts)
        for topping in toppingCosts:
            new_possible = set(possible)
            for cost in possible:
                new_possible.add(cost + topping)
                new_possible.add(cost + 2 * topping)
            possible = new_possible
        min_diff = float('inf')
        result = 0
        for cost in possible:
            diff = abs(cost - target)
            if diff < min_diff or (diff == min_diff and cost < result):
                min_diff = diff
                result = cost
        return result
